sql:
SELECT owner_name
FROM building_owners
WHERE building_id = 300051;

SELECT owner_id, building_id, owner_name, owner_type
FROM building_owners
WHERE owner_id = (SELECT MAX(owner_id) FROM building_owners);

SELECT geo_level_name
FROM geo_levels
WHERE geo_level_id = 0;

SELECT geo_level_name
FROM geo_levels
WHERE geo_level_type = 'country';

SELECT secondary_use_type
FROM building_secondary_uses
WHERE building_id = 99355;

SELECT secondary_use_type, COUNT(*) AS building_count
FROM building_secondary_uses
GROUP BY secondary_use_type;

SELECT * 
FROM geo_levels 
WHERE geo_level_type = 'country';

SELECT geo_level_name
FROM geo_levels
WHERE geo_level_id > 0 AND geo_level_type = 'country';

SELECT COUNT(building_id)
FROM building_construction_materials
WHERE material_type = 'adobe mud';

SELECT material_type
FROM building_construction_materials
WHERE building_id = 99355;

SELECT MIN(geo_level_id) 
FROM geo_levels 
WHERE geo_level_type = 'region';

external_knowledge:
- 'Clay castles' is a metaphorical reference to buildings constructed with 'adobe mud'.;
- 'Ancient structures' suggests buildings with historical value or long-standing history, which may include those made of traditional materials like adobe mud.;
- 'Custodians' refers to the owners of these buildings.;
- 'Other purposes' refers to the secondary use types of the buildings, such as agriculture, hotel, or rental.

- "farming, hospitality, or leasing" corresponds to 'agriculture', 'hotel', and 'rental' in the database;
- "mud or stone" refers to 'adobe mud', 'mud mortar stone', and 'stone flag';
- The "special value" is the hyperbolic tangent of the ratio of the number of buildings owned by an organization to the total number of records in the dataset.

